                                                }`}
                                        >
                                            <Star className={`w-8 h-8 ${rating >= star ? 'fill-yellow-400' : ''}`} />
                                        </button>
                                    ))}
                                </div>

                                <div className="mb-6">
                                    <label className="block text-sm font-medium text-gray-700 mb-2">
                                        Describe your experience
